#!/usr/bin/env pypy
from __future__ import division, print_function

import os
import sys
from collections import deque

def process(grid, a, n, m):
    aux = [[0] * m for _ in range(n)]
    for i in range(n):
        mi = deque()
        for j in range(a):
            while mi and grid[i][j] < mi[-1]:
                mi.pop()
            mi.append(grid[i][j])
        aux[i][0] = mi[0]
        for j in range(a, m):
            if mi[0] == grid[i][j - a]:
                mi.popleft()
            while mi and grid[i][j] < mi[-1]:
                mi.pop()
            mi.append(grid[i][j])
            aux[i][j - a + 1] = mi[0]
    return aux

def main():
    import sys
    input = sys.stdin.read
    data = input().split()
    idx = 0
    n = int(data[idx]); idx += 1
    m = int(data[idx]); idx += 1
    a = int(data[idx]); idx += 1
    b = int(data[idx]); idx += 1
    g0 = int(data[idx]); idx += 1
    x = int(data[idx]); idx += 1
    y = int(data[idx]); idx += 1
    z = int(data[idx]); idx += 1

    MOD = z
    grid = [[0] * m for _ in range(n)]
    current = g0
    for i in range(n):
        for j in range(m):
            grid[i][j] = current % MOD
            current = (current * x + y) % MOD

    # Process rows first (sliding window of size b)
    row_min = [[0] * (m - b + 1) for _ in range(n)]
    for i in range(n):
        q = deque()
        for j in range(b):
            while q and grid[i][j] < q[-1]:
                q.pop()
            q.append(grid[i][j])
        row_min[i][0] = q[0]
        for j in range(b, m):
            if q[0] == grid[i][j - b]:
                q.popleft()
            while q and grid[i][j] < q[-1]:
                q.pop()
            q.append(grid[i][j])
            row_min[i][j - b + 1] = q[0]

    # Process columns of row_min (sliding window of size a)
    total = 0
    for j in range(m - b + 1):
        q = deque()
        for i in range(a):
            while q and row_min[i][j] < q[-1]:
                q.pop()
            q.append(row_min[i][j])
        total += q[0]
        for i in range(a, n):
            if q[0] == row_min[i - a][j]:
                q.popleft()
            while q and row_min[i][j] < q[-1]:
                q.pop()
            q.append(row_min[i][j])
            total += q[0]
    print(total)

if __name__ == "__main__":
    main()
